import React, { useCallback, useEffect, useRef, useState } from 'react';
import { Button, Modal } from '@linm-soft-org/linm-web-common-components';
import type { DocumentPostedLedgerDto, DocumentPostingStatus } from '../../services/bh/ledgerModels';
import { formatDateLocal, formatVnd } from '../../utils/format';
import { pollDocumentPostingStatus } from '../../utils/pollDocumentPostingStatus';
import styles from './VoucherPostedLedgerModal.module.css';
import modalStyles from '../../styles/documentForm.module.css';

const IN_PROGRESS: DocumentPostingStatus[] = ['Queued', 'Processing'];

export interface VoucherPostedLedgerModalProps {
  isOpen: boolean;
  onClose: () => void;
  voucherTitle?: string;
  testIdPrefix: string;
  fetchPostedLedger: () => Promise<DocumentPostedLedgerDto>;
  fetchPostingStatus?: () => Promise<{ postingStatus: DocumentPostingStatus; lastError?: string | null }>;
}

function accountLabel(code: string, name?: string | null): string {
  const trimmed = name?.trim();
  return trimmed ? `${code} — ${trimmed}` : code;
}

function statusLabel(status: DocumentPostingStatus): string {
  switch (status) {
    case 'Queued': return 'Đang chờ ghi sổ';
    case 'Processing': return 'Đang ghi sổ';
    case 'Posted': return 'Đã ghi sổ';
    case 'Failed': return 'Ghi sổ thất bại';
    default: return 'Chưa ghi sổ';
  }
}

export const VoucherPostedLedgerModal: React.FC<VoucherPostedLedgerModalProps> = ({
  isOpen,
  onClose,
  voucherTitle,
  testIdPrefix,
  fetchPostedLedger,
  fetchPostingStatus,
}) => {
  const [loading, setLoading] = useState(false);
  const [polling, setPolling] = useState(false);
  const [data, setData] = useState<DocumentPostedLedgerDto | null>(null);
  const [error, setError] = useState<string | null>(null);
  const cancelledRef = useRef(false);

  const loadLedger = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      let ledger = await fetchPostedLedger();
      if (IN_PROGRESS.includes(ledger.postingStatus) && fetchPostingStatus) {
        setPolling(true);
        await pollDocumentPostingStatus(fetchPostingStatus, { intervalMs: 1000, maxAttempts: 90 });
        if (cancelledRef.current) return;
        ledger = await fetchPostedLedger();
      }
      if (!cancelledRef.current) setData(ledger);
    } catch (e: unknown) {
      if (!cancelledRef.current) {
        setError(e instanceof Error && e.message === 'POSTING_POLL_TIMEOUT'
          ? 'Ghi sổ đang xử lý quá lâu. Vui lòng thử lại sau.'
          : 'Không thể tải dữ liệu sổ cái.');
      }
    } finally {
      if (!cancelledRef.current) {
        setLoading(false);
        setPolling(false);
      }
    }
  }, [fetchPostedLedger, fetchPostingStatus]);

  useEffect(() => {
    if (!isOpen) {
      cancelledRef.current = true;
      setData(null);
      setError(null);
      setPolling(false);
      return;
    }
    cancelledRef.current = false;
    void loadLedger();
    return () => { cancelledRef.current = true; };
  }, [isOpen, loadLedger]);

  const tid = (suffix: string) => `${testIdPrefix}-posted-ledger-${suffix}`;
  const status = data?.postingStatus ?? 'None';
  const showTable = status === 'Posted' && (data?.lines.length ?? 0) > 0;

  return (
    <Modal isOpen={isOpen} onClose={onClose} title="Xem sổ cái" size="lg" data-testid={tid('modal')}>
      {voucherTitle ? (
        <p style={{ marginBottom: 12, fontSize: 14, color: 'var(--color-text-secondary, #6c757d)' }} data-testid={tid('title')}>
          {voucherTitle}
        </p>
      ) : null}

      {loading && !data ? (
        <div className={styles.statusProcessing} data-testid={tid('loading')}>
          <i className="fas fa-spinner fa-spin" /> Đang tải dữ liệu sổ cái…
        </div>
      ) : null}

      {error ? <div className={styles.statusFailed} data-testid={tid('error')}>{error}</div> : null}

      {data ? (
        <>
          <div className={styles.meta} data-testid={tid('meta')}>
            <span><strong>Tiến trình ghi sổ:</strong> {statusLabel(status)}</span>
            {data.journalEntryCode ? <span><strong>Bút toán:</strong> {data.journalEntryCode}</span> : null}
            {data.entryDate ? <span><strong>Ngày hạch toán:</strong> {formatDateLocal(data.entryDate)}</span> : null}
            {data.postedAt ? <span><strong>Ghi sổ lúc:</strong> {formatDateLocal(data.postedAt)}</span> : null}
          </div>

          {IN_PROGRESS.includes(status) ? (
            <div className={styles.statusProcessing} data-testid={tid('in-progress')}>
              <i className={`fas ${polling || loading ? 'fa-spinner fa-spin' : 'fa-clock'}`} />
              {data.message ?? (status === 'Processing' ? 'Đang ghi sổ…' : 'Đang chờ ghi sổ…')}
            </div>
          ) : null}

          {status === 'Failed' ? (
            <div className={styles.statusFailed} data-testid={tid('failed')}>
              {data.lastError ?? data.message ?? 'Ghi sổ thất bại.'}
            </div>
          ) : null}

          {!showTable && data.message && status !== 'Failed' && !IN_PROGRESS.includes(status) ? (
            <div className={styles.statusMessage} data-testid={tid('message')}>{data.message}</div>
          ) : null}

          {showTable ? (
            <div className={styles.tableWrap} data-testid={tid('table-wrap')}>
              <table className={styles.table} data-testid={tid('table')}>
                <thead>
                  <tr>
                    <th className={styles.lineNoCol}>#</th>
                    <th>Tài khoản Nợ</th>
                    <th>Tài khoản Có</th>
                    <th className={styles.amountCol}>Số tiền</th>
                    <th>Diễn giải</th>
                  </tr>
                </thead>
                <tbody>
                  {data.lines.map(line => (
                    <tr key={line.lineNo} data-testid={tid(`line-${line.lineNo}`)}>
                      <td className={styles.lineNoCol}>{line.lineNo}</td>
                      <td>{accountLabel(line.debitAccountCode, line.debitAccountName)}</td>
                      <td>{accountLabel(line.creditAccountCode, line.creditAccountName)}</td>
                      <td className={styles.amountCol}>{formatVnd(line.amount)}</td>
                      <td>{line.description ?? '—'}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ) : null}
        </>
      ) : null}

      <div className={modalStyles.modalActions}>
        <Button variant="secondary" onClick={onClose} data-testid={tid('close')}>Đóng</Button>
        {data && IN_PROGRESS.includes(status) ? (
          <Button variant="primary" onClick={() => void loadLedger()} loading={loading} data-testid={tid('refresh')}>
            Làm mới
          </Button>
        ) : null}
      </div>
    </Modal>
  );
};
