import { navigateToUrl } from 'single-spa';
import { isStandalone } from '../dev/isStandalone';

declare global {
  interface Window {
    __LINM_OPEN_WORKSPACE_TAB__?: (input: { path: string; title: string }) => void;
  }
}

/** Mở route cross-MFE (vd. `/kt/pt/{id}`) qua shell hoặc standalone. */
export function openCrossMfePath(path: string, navigate: (p: string) => void): void {
  const normalized = path.startsWith('/') ? path : `/${path}`;
  if (typeof window.__LINM_OPEN_WORKSPACE_TAB__ === 'function') {
    window.__LINM_OPEN_WORKSPACE_TAB__({ path: normalized, title: normalized });
    return;
  }
  if (isStandalone) {
    navigate(normalized);
    return;
  }
  navigateToUrl(normalized);
}
